select DISTINCT
a.sop_id,SUBSTRING(b.sop_name, -3) as type,b.sop_name, b.version,c.stage_id,c.line_id
from mes_oa_sop a
left join mes_sop b on a.sop_id = b.sop_id
left join mes_upload_terminal_page c on a.sop_id = c.sop_id
WHERE b.version = #{version}
AND c.type = #{type}
AND c.line_id = #{lineId}
AND c.stage_id = #{stageId}
AND c.status = 2

SELECT a.sop_id,b.sop_name, b.version,c.material_id,c.process_id,c.type
from mes_oa_sop a
left join mes_sop b on a.sop_id = b.sop_id
left join mes_upload_terminal_page c on a.sop_id = c.sop_id
WHERE b.version = #{version}
AND c.material_id = #{materialId}
AND c.process_id = #{processId}
AND c.type = #{type}

SELECT A.sop_id FROM mes_oa_sop A
left join mes_sop B ON A.sop_id = B.sop_id
WHERE A.material_id = #{materialId} AND B.type = #{type}

