SELECT
* FROM(SELECT A.sop_id,B.sop_name,A.create_time
FROM
mes_upload_terminal_page A,
mes_sop B
WHERE
A.sop_id = B.sop_id
AND A.model_id = #{modelId}
AND A.line_id = #{lineId}
AND A.stage_id = #{stageId}
AND A.process_id = #{processId}
AND A.material_id = #{materialId}
AND A.terminal_id = #{terminalId}
AND A.`status` = '2'
AND A.type = #{type}
ORDER BY A.create_time desc
LIMIT 1) a

